import React, { useState, useEffect, useRef } from 'react';
import { Play, Pause, Volume2, VolumeX, Radio, AlertCircle, Headphones } from 'lucide-react';
import { RadioConfig } from '../types';
import { GoogleGenAI } from "@google/genai";

interface Props {
  config: RadioConfig;
}

const RadioPlayer: React.FC<Props> = ({ config }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [isMuted, setIsMuted] = useState(false);
  const [volume, setVolume] = useState(0.8);
  const [status, setStatus] = useState<'checking' | 'online' | 'fallback'>('checking');
  const [quote, setQuote] = useState<string | null>(null);
  const audioRef = useRef<HTMLAudioElement>(null);

  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  useEffect(() => {
    const fetchInspiration = async () => {
      try {
        const response = await ai.models.generateContent({
          model: 'gemini-3-flash-preview',
          contents: "Donne une courte citation inspirante ou un verset apaisant en français pour une application de radio spirituelle. Juste le texte.",
        });
        setQuote(response.text);
      } catch (e) {
        console.error("Gemini failed", e);
      }
    };
    fetchInspiration();
  }, []);

  const checkStream = async () => {
    setStatus('checking');
    try {
      const response = await fetch(config.streamUrl, { method: 'HEAD', mode: 'no-cors' });
      // Note: Opaque responses from no-cors are tricky, but if the browser can't even start fetching, it's down
      setStatus('online');
    } catch (e) {
      console.warn("Stream unavailable, switching to fallback", e);
      setStatus('fallback');
    }
  };

  useEffect(() => {
    checkStream();
  }, [config.streamUrl]);

  const togglePlay = () => {
    if (audioRef.current) {
      if (isPlaying) {
        audioRef.current.pause();
      } else {
        audioRef.current.play().catch(e => {
          console.error("Playback failed", e);
          setStatus('fallback');
        });
      }
      setIsPlaying(!isPlaying);
    }
  };

  const activeUrl = status === 'fallback' ? config.fallbackUrl : config.streamUrl;

  return (
    <div className="flex flex-col items-center gap-8 py-10 animate-in fade-in duration-700">
      <div className="relative group">
        <div className="w-64 h-64 lg:w-80 lg:h-80 rounded-full bg-zinc-900 flex items-center justify-center border-4 border-emerald-500/20 shadow-2xl overflow-hidden">
          <div className="absolute inset-0 bg-gradient-to-tr from-emerald-500/10 to-transparent"></div>
          {isPlaying && (
            <div className="absolute inset-0 flex items-center justify-center opacity-20 pointer-events-none">
              <div className="w-full h-1 bg-emerald-500 animate-[bounce_1s_infinite]"></div>
              <div className="w-full h-1 bg-emerald-400 animate-[bounce_1.2s_infinite]"></div>
              <div className="w-full h-1 bg-emerald-600 animate-[bounce_0.8s_infinite]"></div>
            </div>
          )}
          <Headphones size={120} className="text-zinc-800" />
        </div>

        {status === 'online' && (
          <div className="absolute -top-2 -right-2 flex items-center gap-2 bg-red-500 px-3 py-1 rounded-full text-[10px] font-bold tracking-widest uppercase live-pulse text-white shadow-lg">
            <span className="w-2 h-2 bg-white rounded-full"></span>
            Live
          </div>
        )}

        {status === 'fallback' && (
          <div className="absolute -top-2 -right-2 flex items-center gap-2 bg-amber-500 px-3 py-1 rounded-full text-[10px] font-bold tracking-widest uppercase text-white shadow-lg">
            <AlertCircle size={12} />
            Playlist Locale
          </div>
        )}
      </div>

      <div className="text-center space-y-2">
        <h1 className="text-3xl lg:text-4xl font-bold tracking-tight text-white">{config.stationName}</h1>
        <p className="text-zinc-400 text-sm font-medium italic max-w-xs mx-auto">
          {quote ? `« ${quote} »` : "Votre source de sérénité quotidienne"}
        </p>
      </div>

      <div className="w-full max-w-sm glass rounded-3xl p-6 space-y-6">
        <audio 
          ref={audioRef} 
          src={activeUrl} 
          muted={isMuted}
          onEnded={() => setIsPlaying(false)}
        />

        <div className="flex items-center justify-center gap-8">
          <button 
            onClick={() => setIsMuted(!isMuted)}
            className="p-3 text-zinc-400 hover:text-white transition-colors"
          >
            {isMuted || volume === 0 ? <VolumeX size={24} /> : <Volume2 size={24} />}
          </button>

          <button 
            onClick={togglePlay}
            className="w-20 h-20 bg-emerald-500 hover:bg-emerald-400 text-zinc-950 rounded-full flex items-center justify-center transition-all transform active:scale-95 shadow-[0_0_20px_rgba(16,185,129,0.4)]"
          >
            {isPlaying ? <Pause size={36} fill="currentColor" /> : <Play size={36} className="ml-1" fill="currentColor" />}
          </button>

          <button 
            onClick={checkStream}
            className="p-3 text-zinc-400 hover:text-white transition-colors"
          >
            <Radio size={24} className={status === 'checking' ? 'animate-spin' : ''} />
          </button>
        </div>

        <div className="flex items-center gap-4 px-2">
          <Volume2 size={16} className="text-zinc-500" />
          <input 
            type="range" 
            min="0" 
            max="1" 
            step="0.01" 
            value={volume}
            onChange={(e) => {
              const val = parseFloat(e.target.value);
              setVolume(val);
              if (audioRef.current) audioRef.current.volume = val;
            }}
            className="flex-grow accent-emerald-500 h-1 bg-zinc-800 rounded-lg appearance-none cursor-pointer"
          />
        </div>
      </div>

      <div className="text-zinc-500 text-xs flex items-center gap-2">
        <div className={`w-2 h-2 rounded-full ${status === 'online' ? 'bg-emerald-500' : status === 'fallback' ? 'bg-amber-500' : 'bg-zinc-700'}`}></div>
        Flux: {status === 'online' ? 'Direct Actif' : status === 'fallback' ? 'Mode Secours (Serveur)' : 'Vérification...'}
      </div>
    </div>
  );
};

export default RadioPlayer;

import React, { useState, useEffect } from 'react';
import { Clock, MapPin, Loader2, ChevronRight, Moon, Sun, Sunrise } from 'lucide-react';
import { ALADHAN_API_BASE } from '../constants';
import { PrayerTimings } from '../types';

const PrayerTimes: React.FC = () => {
  const [timings, setTimings] = useState<PrayerTimings | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [city, setCity] = useState("Ma Position");

  const fetchTimes = async (lat: number, lon: number) => {
    try {
      const response = await fetch(`${ALADHAN_API_BASE}?latitude=${lat}&longitude=${lon}&method=2`);
      const data = await response.json();
      if (data.code === 200) {
        setTimings(data.data.timings);
      } else {
        throw new Error("Erreur API Aladhan");
      }
    } catch (err) {
      setError("Impossible de charger les horaires.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    if (!navigator.geolocation) {
      setError("Géolocalisation non supportée.");
      setLoading(false);
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (pos) => fetchTimes(pos.coords.latitude, pos.coords.longitude),
      () => {
        // Default to Paris if geolocation fails
        setError("Géolocalisation refusée. Utilisation de Paris par défaut.");
        fetchTimes(48.8566, 2.3522);
      }
    );
  }, []);

  const getNextPrayer = () => {
    if (!timings) return null;
    const now = new Date();
    const currentTime = now.getHours() * 60 + now.getMinutes();

    const prayerKeys: (keyof PrayerTimings)[] = ['Fajr', 'Dhuhr', 'Asr', 'Maghrib', 'Isha'];
    for (const key of prayerKeys) {
      const [h, m] = timings[key].split(':').map(Number);
      const prayerTime = h * 60 + m;
      if (prayerTime > currentTime) return key;
    }
    return 'Fajr'; // Next day
  };

  const nextPrayer = getNextPrayer();

  const PrayerCard = ({ name, time, icon: Icon }: { name: string, time: string, icon: any }) => (
    <div className={`p-4 rounded-2xl flex items-center justify-between transition-all ${nextPrayer === name ? 'bg-emerald-500 text-zinc-950 shadow-lg scale-105' : 'glass text-zinc-100'}`}>
      <div className="flex items-center gap-4">
        <div className={`p-2 rounded-xl ${nextPrayer === name ? 'bg-zinc-950/20' : 'bg-zinc-800'}`}>
          <Icon size={20} />
        </div>
        <div>
          <div className="text-xs font-bold uppercase tracking-wider opacity-80">{name}</div>
          <div className="text-xl font-bold">{time}</div>
        </div>
      </div>
      {nextPrayer === name && <ChevronRight size={24} />}
    </div>
  );

  if (loading) return (
    <div className="flex flex-col items-center justify-center py-20 gap-4">
      <Loader2 size={40} className="text-emerald-500 animate-spin" />
      <p className="text-zinc-500 animate-pulse">Chargement des horaires...</p>
    </div>
  );

  return (
    <div className="space-y-8 py-6 animate-in slide-in-from-bottom-4 duration-500">
      <div className="flex items-center justify-between">
        <div>
          <h1 className="text-2xl font-bold">Horaires de Prières</h1>
          <div className="flex items-center gap-2 text-zinc-500 text-sm mt-1">
            <MapPin size={14} />
            <span>{city}</span>
          </div>
        </div>
        <div className="text-right">
          <div className="text-xs text-zinc-500 uppercase tracking-widest font-bold">Date Hejir</div>
          <div className="text-sm font-medium text-emerald-500">
            {new Date().toLocaleDateString('fr-FR', { weekday: 'long', day: 'numeric', month: 'long' })}
          </div>
        </div>
      </div>

      {error && <div className="bg-amber-500/10 border border-amber-500/20 text-amber-500 px-4 py-2 rounded-lg text-sm">{error}</div>}

      <div className="grid gap-4">
        {timings && (
          <>
            <PrayerCard name="Fajr" time={timings.Fajr} icon={Sunrise} />
            <PrayerCard name="Dhuhr" time={timings.Dhuhr} icon={Sun} />
            <PrayerCard name="Asr" time={timings.Asr} icon={Sun} />
            <PrayerCard name="Maghrib" time={timings.Maghrib} icon={Moon} />
            <PrayerCard name="Isha" time={timings.Isha} icon={Moon} />
          </>
        )}
      </div>

      <div className="glass p-6 rounded-3xl border-dashed border-zinc-700">
        <h3 className="text-sm font-bold uppercase tracking-widest text-zinc-500 mb-2">Note Spirituelle</h3>
        <p className="text-zinc-300 text-sm leading-relaxed">
          La prière est le pilier de la religion. Veillez à respecter les horaires de votre localité. Les données sont fournies par l'API Aladhan basée sur la méthode de la Ligue Islamique Mondiale.
        </p>
      </div>
    </div>
  );
};

